class Config:
    def __init__(self, chunkchildrecords=100, chunkonchangeof=""):
        self.chunkchildrecords = chunkchildrecords
        self.chunkonchangeof = chunkonchangeof

    def to_dict(self):
        return {
            "chunkchildrecords": self.chunkchildrecords,
            "chunkonchangeof": self.chunkonchangeof,
        }

def solve(*args):
    config = Config()
    return config.to_dict()
